import org.junit.jupiter.api.Test;

class RulePatternMatchTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void filterJoinPatternCapturesInputsAndCondition() {
		Filter filter = new Filter(new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x")),
				new Compare(new Var("s"), new ValueConstant(VF.createIRI("urn:s")), Compare.CompareOp.EQ));
		PlanIr ir = TupleExprToIr.convert(filter);
		RulePattern pattern = filter("f", join("j", capture("left"), capture("right")), scalar("cond"));

		Optional<RuleCapture> capture = pattern.match(ir, ir.root());

		assertTrue(capture.isPresent());
		assertEquals(4, capture.get().nodes().size());
		assertTrue(capture.get().scalars().containsKey("cond"));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}
}
